// Expects msg.responseBuffer.buffer to contain the raw bytes from Modbus

// Example input based on your provided message:
// msg.payload = [17139, 655];
// msg.responseBuffer = { data: [ 17139, 655 ], buffer: [ 66, 243, 2, 143 ] };

// Check if the necessary buffer exists
if (msg.responseBuffer && msg.responseBuffer.buffer && msg.responseBuffer.buffer.length >= 4) {
 // Create a Buffer object from the raw byte array
 // The PAC3100 seems to send the bytes in Big-Endian order already [MSB_reg1, LSB_reg1, MSB_reg2, LSB_reg2]
 const buf = Buffer.from(msg.responseBuffer.buffer);

 // Read the buffer as a 32-bit Big-Endian float starting at offset 0
 const floatValue = buf.readFloatBE(0);

 // Round to 2 decimal places
 msg.payload = parseFloat(floatValue.toFixed(2));

 // Optional: Log the result for debugging
 // node.log("Converted value: " + msg.payload);

} else {
 // Handle cases where the buffer is missing or too short
 node.error("Input message does not contain a valid responseBuffer.buffer", msg);
 // Set payload to null or keep it as is, depending on desired error handling
 msg.payload = null;
}

// Pass the message object along the flow
return msg;

