// Aceita payload number (corrente/tensão) ou objeto com campos de energia/demanda
let ok = false;
const v = msg && msg.payload;
if (typeof v === 'number' && Number.isFinite(v)) ok = true;
else if (v && typeof v === 'object') {
 // seus decoders de energia/demanda mandam objetos com estes campos
 if ('metric' in v || 'wh' in v || 'kwh' in v || 'varh' in v || 'seconds' in v) ok = true;
}
if (ok) {
 flow.set('last_modbus_sample_ts', Date.now());
 flow.set('last_modbus_sample', v); // opcional, útil pra diagnóstico
}
return null; // não interfere no fluxo principal

const THRESH = 8000; // 8 s
const COOLDOWN = 5000; // evita tiros em sequência

const now = Date.now();
const last = flow.get('last_modbus_sample_ts') || 0;
const lastKick = flow.get('last_modbus_kick_ts') || 0;
const idle = now - last;

node.status({
  fill: idle > THRESH ? 'red' : 'green',
  shape: 'dot',
  text: `idle ${Math.round(idle / 1000)}s`
});

if (idle > THRESH && (now - lastKick) > COOLDOWN) {
  flow.set('last_modbus_kick_ts', now);
  // dispara o início da cadeia (seu delay de 200 ms leva até Corrente L1)
  return { payload: 'watchdog-kick' };
}

return null;

const v = msg && msg.payload;
if (v && typeof v === 'object' && (
 v.metric === 'energy_active_wh' ||
 v.metric === 'energy_reactive_varh' ||
 v.metric === 'demand_length_s' ||
 v.metric === 'demand_elapsed_s'
)) {
 // marcou uma coleta de consumo concluída
 flow.set('last_consumo_ts', Date.now());

 // libera a trava (coleta concluiu)
 flow.set('consumo_inflight_until', 0);
}
return null;

// --- Parâmetros ---
const PERIOD_MS = flow.get('consumo_period_ms') ?? (15 * 60 * 1000); // 15 min
const LOCK_MS = flow.get('consumo_lock_ms') ?? 60000;            // trava por até 60s

// --- Estado ---
const now = Date.now();
const lastOK = flow.get('last_consumo_ts') || 0;          // última coleta OK
const lockUntil = flow.get('consumo_inflight_until') || 0;   // trava ativa até quando
const locked = now < lockUntil;

// --- Decisão ---
const due = (now - lastOK >= PERIOD_MS) && !locked;

// --- Status no editor ---
let txt;
if (locked) {
    const secs = Math.max(0, Math.floor((lockUntil - now) / 1000));
    txt = `aguardando coleta atual (${secs}s)`;
} else if (due) {
    txt = 'coletar consumo';
} else {
    const mins = Math.max(0, Math.floor((PERIOD_MS - (now - lastOK)) / 60000));
    txt = `pular (${mins}m)`;
}
node.status({ fill: due ? 'green' : (locked ? 'blue' : 'yellow'), shape: 'dot', text: txt });

// --- Saídas ---
if (due) {
    // ativa trava para evitar 2 coletas em paralelo
    flow.set('consumo_inflight_until', now + LOCK_MS);
    return [{ ...msg }, null];   // SAÍDA 1 → “Energia Ativa 801”
}

return [null, { payload: 'skip-consumo' }]; // SAÍDA 2 → bypass para Corrente L1

