// Espera msg.payload = { ts, metric, wh, kwh } vindo do "Decode Double BE → Wh / kWh"

const p = msg.payload || {};
const ts = p.ts || new Date().toISOString();

// 1) Captura leitura atual (prioriza Wh; se não tiver, usa kWh e converte p/ Wh)
let atualWh = Number.isFinite(p.wh) ? Number(p.wh)
    : (Number.isFinite(p.kwh) ? Number(p.kwh) * 1000 : NaN);

if (!Number.isFinite(atualWh)) {
    node.error("Leitura inválida do decoder (esperado payload.wh ou payload.kwh numéricos).", msg);
    return null;
}

// 2) Recupera última leitura
const prev = flow.get("prev_wh_total");
let deltaWh = null;
let reset = false;

if (Number.isFinite(prev)) {
    deltaWh = atualWh - prev;
    if (deltaWh < 0) {          // reset/overflow detectado
        deltaWh = 0;
        reset = true;
    }
}

// 3) Atualiza memória para próxima varredura
flow.set("prev_wh_total", atualWh);

// 4) Monta payload final p/ banco
msg.payload = {
    DateTime: ts,                                // mantém timestamp do decoder
    wh_total: Math.round(atualWh),         // se quiser manter fração, remova o round
    kwh_intervalo: deltaWh == null ? null : (deltaWh / 1000),
    reset_flag: reset
};

return msg;

